class URLParser {
    class func parseUrl(_ url: URL) {
        let scheme = url.scheme ?? ""
        if scheme == "https" {
            guard let pathComponents = url.path.components(separatedBy: "/") else { return }
            
            switch pathComponents[1] {
                case "profile":
                    self.navigateToProfile(pathComponents)
                case "payment", "confirm":
                    self.navigateToPayment()
                case "admin":
                    switch pathComponents[2] {
                        case "settings":
                            self.navigateToAdminSettings()
                        default:
                            print("Invalid admin path")
                    }
                default:
                    print("Invalid URL scheme or path")
            }
        } else {
            print("Only https scheme supported")
        }
    }

    class func navigateToProfile(_ components: [String]) {
        let storyboard = UIStoryboard(name: "Main", bundle: nil)
        let destinationVC = storyboard.instantiateViewController(withIdentifier: "ProfileViewController") as! ProfileViewController
        destinationVC.profileId = Int(components[2])
        let navController = UIApplication.shared.keyWindow?.rootViewController as? UINavigationController
        navController?.pushViewController(destinationVC, animated: true)
    }

    class func navigateToPayment() {
        let storyboard = UIStoryboard(name: "Main", bundle: nil)
        let destinationVC = storyboard.instantiateViewController(withIdentifier: "PaymentConfirmationViewController") as! PaymentConfirmationViewController
        let navController = UIApplication.shared.keyWindow?.rootViewController as? UINavigationController
        navController?.pushViewController(destinationVC, animated: true)
    }

    class func navigateToAdminSettings() {
        let storyboard = UIStoryboard(name: "Main", bundle: nil)
        let destinationVC = storyboard.instantiateViewController(withIdentifier: "AdminSettingsViewController") as! AdminSettingsViewController
        let navController = UIApplication.shared.keyWindow?.rootViewController as? UINavigationController
        navController?.pushViewController(destinationVC, animated: true)
    }
}

class AppDelegateHelper: UIResponder, UIApplicationDelegate {
