                    default:
                        print("Invalid profile link")
                }
            } else {
                print("No path found in URL")
            }
        }
        
        return true
    }

    func application(_ app: UIApplication, continue userActivity: NSUserActivity, restorationHandler: @escaping ([UIParticipant]) -> Void) -> Bool {
